   100→export async function assertCanSendAiMessage(tenantId: string) {
   101→  await connectToDatabase();
   102→  const subscription = await TenantSubscription.findOne({ tenantId });
   103→  if (!subscription) return;
   104→
   105→  const allowance = subscription.monthlyMessageLimit + subscription.extraMessageCredits;
   106→  if (allowance <= 0) return;
   107→
   108→  const grace = Number((subscription as any).graceMessageLimit ?? 20);
   109→  if (subscription.usedMessages >= allowance + Math.max(0, grace)) {
   110→    throw new Error("AI message limit exceeded. Add a message pack or upgrade the plan.");
   111→  }
   112→}
   113→
   114→export async function recordAiMessageUsage(tenantId: string) {
   115→  const subscription = await TenantSubscription.findOneAndUpdate(
   116→    { tenantId },
   117→    { $inc: { usedMessages: 1 } },
   118→    { new: true, upsert: false }
   119→  );
   120→
   121→  if (!subscription) return;
   122→  const allowance = subscription.monthlyMessageLimit + subscription.extraMessageCredits;
   123→  if (allowance <= 0) return;
   124→
   125→  const used = subscription.usedMessages || 0;
   126→  const grace = Number((subscription as any).graceMessageLimit ?? 20);
   127→  const percent = Math.round((used / allowance) * 100);
   128→  const remaining = Math.max(allowance - used, 0);
   129→  const graceRemaining = Math.max(allowance + grace - used, 0);
   130→
   131→  if (percent >= 80 || used >= allowance) {
   132→    await publishRealtimeEvent(tenantId, "billing.usage.updated", {
   133→      usage: {
   134→        usedMessages: used,
   135→        monthlyMessageLimit: subscription.monthlyMessageLimit,
   136→        extraMessageCredits: subscription.extraMessageCredits,
   137→        graceMessageLimit: grace,
   138→        percent,
   139→        remaining,
   140→        graceRemaining,
   141→        level: used >= allowance ? "grace" : percent >= 90 ? "danger" : "warning",
   142→      },
   143→    }).catch(() => undefined);
   144→  }
   145→}
