   235→export async function handleStripeEvent(event: Stripe.Event) {
   236→  await connectToDatabase();
   237→  
   238→  const eventIdToTrack = event.type === "checkout.session.completed" 
   239→    ? (event.data.object as any).id 
   240→    : event.id;
   241→
   242→  const exists = await PaymentEvent.exists({ stripeEventId: eventIdToTrack });
   243→  if (exists) return;
   244→
   245→  let paymentEvent;
   246→  try {
   247→    paymentEvent = await PaymentEvent.create({
   248→      stripeEventId: eventIdToTrack,
   249→      type: event.type,
   250→      payload: event,
   251→      status: "received"
   252→    });
   253→  } catch (error: any) {
   254→    if (error?.code === 11000) return;
   255→    throw error;
   256→  }
   257→
   258→  try {
   259→    if (event.type === "checkout.session.completed") {
   260→      await handleCheckoutCompleted(event.data.object as Stripe.Checkout.Session);
   261→    } else if (event.type === "customer.subscription.updated") {
   262→      await handleSubscriptionUpdated(event.data.object as Stripe.Subscription);
   263→    } else if (event.type === "customer.subscription.deleted") {
   264→      await handleSubscriptionDeleted(event.data.object as Stripe.Subscription);
   265→    } else if (event.type === "invoice.payment_succeeded") {
   266→      await handleInvoicePaymentSucceeded(event.data.object as Stripe.Invoice);
   267→    } else if (event.type === "invoice.payment_failed") {
   268→      await handleInvoicePaymentFailed(event.data.object as Stripe.Invoice);
   269→    }
   270→    paymentEvent.status = "processed";
   271→    await paymentEvent.save();
   272→  } catch (error) {
   273→    paymentEvent.status = "error";
   274→    paymentEvent.error = error instanceof Error ? error.message : "Stripe webhook error";
   275→    await paymentEvent.save();
   276→    throw error;
   277→  }
