   280→async function handleCheckoutCompleted(session: Stripe.Checkout.Session) {
   281→  const tenantId = session.metadata?.tenantId;
   282→  const kind = session.metadata?.kind;
   283→  const itemId = session.metadata?.itemId;
   284→  if (!tenantId || !kind || !itemId) return;
   285→  if (!Types.ObjectId.isValid(tenantId) || !Types.ObjectId.isValid(itemId)) return;
   286→
   287→  if (kind === "plan") {
   288→    const plan = await BillingPlan.findOne({
   289→      _id: itemId,
   290→      $or: [{ tenantId: null }, { tenantId }, { tenantId: { $exists: false } }],
   291→      createdByAdmin: true,
   292→      isActive: true
   293→    });
   294→    if (!plan) return;
   295→    const stripeSubscriptionId = typeof session.subscription === "string" ? session.subscription : "";
   296→    const stripeSubscription = stripeSubscriptionId
   297→      ? await getStripe().subscriptions.retrieve(stripeSubscriptionId)
   298→      : null;
   299→    const currentPeriodEnd = stripeSubscription ? getSubscriptionPeriodEnd(stripeSubscription) : null;
   300→
   301→    await TenantSubscription.findOneAndUpdate(
   302→      { tenantId },
   303→      {
   304→        $set: {
   305→          tenantId,
   306→          planId: plan._id,
   307→          stripeCustomerId: typeof session.customer === "string" ? session.customer : "",
   308→          stripeSubscriptionId,
   309→          status: stripeSubscription?.status || "active",
   310→          monthlyMessageLimit: plan.aiMessageLimit,
   311→          usedMessages: 0,
   312→          ...(currentPeriodEnd ? { currentPeriodEnd } : {})
   313→        }
   314→      },
   315→      { upsert: true, new: true }
   316→    );
   317→  }
   318→
   319→  if (kind === "pack") {
   320→    if (session.payment_status !== "paid") return;
   321→
   322→    const pack = await MessagePack.findOne({
   323→      _id: itemId,
   324→      $or: [{ tenantId: null }, { tenantId }, { tenantId: { $exists: false } }],
   325→      createdByAdmin: true,
   326→      isActive: true
   327→    });
   328→    if (!pack) return;
   329→    await TenantSubscription.findOneAndUpdate(
