     6→const QUOTA_KEY_PREFIX = "quota:ai_messages";
     7→const MONGO_SYNC_EVERY = 10;
     8→
     9→export function quotaRedisKey(tenantId: string): string {
    10→  const now = new Date();
    11→  const yyyyMM = `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, "0")}`;
    12→  return `${QUOTA_KEY_PREFIX}:${tenantId}:${yyyyMM}`;
    13→}
    14→
    15→function secondsUntilEndOfMonth(): number {
    16→  const now = new Date();
    17→  const endOfMonth = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1, 0, 0, 0));
    18→  return Math.max(60, Math.floor((endOfMonth.getTime() - now.getTime()) / 1000));
    19→}
    20→
    21→async function getSubscriptionLimit(tenantId: string): Promise<{ limit: number; usedMessages: number } | null> {
    22→  await connectToDatabase();
    23→  const subscription = await TenantSubscription.findOne({ tenantId }).lean();
    24→  if (!subscription) return null;
    25→  const limit = (subscription.monthlyMessageLimit ?? 0) + (subscription.extraMessageCredits ?? 0);
    26→  return { limit, usedMessages: subscription.usedMessages ?? 0 };
    27→}
