    29→async function syncRedisCounterToMongo(tenantId: string, redisCount: number): Promise<void> {
    30→  try {
    31→    await connectToDatabase();
    32→    await TenantSubscription.updateOne(
    33→      { tenantId },
    34→      { $set: { usedMessages: redisCount } }
    35→    );
    36→  } catch (err) {
    37→    logger.warn("quota.mongo_sync_failed", {
    38→      tenantId,
    39→      error: err instanceof Error ? err.message : "unknown",
    40→    });
    41→  }
    42→}
    43→
    44→/**
    45→ * Atomically assert and reserve a quota slot using Redis INCR.
    46→ *
    47→ * Design decisions:
    48→ * - Redis key: quota:ai_messages:{tenantId}:{YYYY-MM} — monthly, per-tenant, isolated.
    49→ * - On first use each month: SET NX (initialize from MongoDB usedMessages) + EXPIRE.
    50→ * - INCR then compare against limit; if exceeded: DECR + throw.
    51→ * - MongoDB sync: every MONGO_SYNC_EVERY increments (fire-and-forget).
    52→ * - Redis down + free plan (limit ≤ 200): fail closed (use MongoDB fallback).
    53→ * - Redis down + paid plan: fail open with warning log.
    54→ *
    55→ * Caller should NOT also call recordAiMessageUsage() when using this function —
    56→ * the increment is embedded here. Use the legacy billing.ts functions only on the
    57→ * old code path that hasn't migrated to quota.ts yet.
    58→ */
    59→export async function assertAndReserveQuota(tenantId: string): Promise<void> {
    60→  const sub = await getSubscriptionLimit(tenantId);
    61→  if (!sub) return;
    62→  if (sub.limit <= 0) return;
    63→
    64→  const key = quotaRedisKey(tenantId);
    65→  const ttl = secondsUntilEndOfMonth();
    66→
    67→  try {
    68→    await redis.set(key, String(sub.usedMessages), "EX", ttl, "NX");
    69→
    70→    const newCount = await redis.incr(key);
    71→
    72→    if (newCount > sub.limit) {
    73→      await redis.decr(key);
    74→      throw new Error("تم استهلاك رصيد رسائل AI لهذه الخطة. اشتر باقة رسائل إضافية أو غيّر الخطة.");
    75→    }
    76→
    77→    if (newCount % MONGO_SYNC_EVERY === 0) {
    78→      void syncRedisCounterToMongo(tenantId, newCount);
    79→    }
    80→  } catch (error) {
    81→    const isQuotaError = error instanceof Error && error.message.includes("رصيد");
    82→    if (isQuotaError) throw error;
    83→
    84→    logger.warn("quota.redis_unavailable_fallback", {
    85→      tenantId,
    86→      error: error instanceof Error ? error.message : "unknown",
    87→    });
    88→
    89→    // Fail closed for free/limited plans (limit <= 200 messages)
    90→    if (sub.limit <= 200) {
    91→      if (sub.usedMessages >= sub.limit) {
    92→        throw new Error("تم استهلاك رصيد رسائل AI لهذه الخطة. اشتر باقة رسائل إضافية أو غيّر الخطة.");
    93→      }
    94→    } else {
    95→      // Paid plans: fail open — log and allow the request
    96→      logger.error("quota.redis_down_paid_plan_allowed", {
    97→        tenantId,
    98→        mongoUsed: sub.usedMessages,
    99→        limit: sub.limit,
   100→      });
   101→    }
   102→  }
   103→}
   104→
   105→export async function getQuotaStatus(tenantId: string): Promise<{
   106→  used: number;
   107→  limit: number;
   108→  redisCount: number;
   109→  source: "redis" | "mongo";
   110→}> {
   111→  const sub = await getSubscriptionLimit(tenantId);
   112→  const key = quotaRedisKey(tenantId);
   113→
   114→  let redisCount = 0;
   115→  try {
   116→    const val = await redis.get(key);
   117→    redisCount = val ? parseInt(val, 10) : 0;
   118→  } catch {
   119→    // Redis unavailable
   120→  }
   121→
   122→  return {
   123→    used: sub?.usedMessages ?? 0,
   124→    limit: sub?.limit ?? 0,
   125→    redisCount,
   126→    source: redisCount > 0 ? "redis" : "mongo",
   127→  };
   128→}
   129→
   130→/**
   131→ * Flush Redis counter to MongoDB immediately (e.g. on billing period end or admin sync).
   132→ */
   133→export async function flushQuotaToMongo(tenantId: string): Promise<void> {
   134→  const key = quotaRedisKey(tenantId);
   135→  try {
   136→    const val = await redis.get(key);
   137→    if (val !== null) {
   138→      await syncRedisCounterToMongo(tenantId, parseInt(val, 10));
   139→    }
   140→  } catch (err) {
   141→    logger.warn("quota.flush_failed", {
   142→      tenantId,
   143→      error: err instanceof Error ? err.message : "unknown",
   144→    });
   145→  }
   146→}
