/**
 * plan-resolver.ts
 *
 * Resolves a tenant's current plan and its features.
 * BillingPlan.features[] is the single source of truth.
 * PLAN_DEFAULTS is no longer consulted here.
 */

import { connectToDatabase } from "@/lib/mongodb";
import { TenantSubscription, BillingPlan, Entitlement } from "@/lib/models";
import type { PlanFeature } from "@/lib/models/billing-plan";

export interface ResolvedFeature {
  key: string;
  type: "boolean" | "quota" | "count" | "storage" | "metered";
  enabled: boolean;
  limit: number;
  resetPeriod: "monthly" | "yearly" | "never";
  overageAllowed: boolean;
  overagePriceCents: number;
  unit: string;
  source: "plan" | "override" | "default";
}

export interface ResolvedPlan {
  planId: string | null;
  planName: string;
  planSlug: string;
  features: Record<string, ResolvedFeature>;
  status: string;
}

/**
 * Resolves all features for a tenant.
 * Priority: tenant-level Entitlement override > plan features > safe defaults.
 */
export async function resolveTenantPlan(tenantId: string): Promise<ResolvedPlan> {
  await connectToDatabase();

  const subscription = await TenantSubscription.findOne({ tenantId })
    .populate("planId")
    .lean();

  const plan = subscription?.planId as any;
  const features: Record<string, ResolvedFeature> = {};

  // Build feature map from plan
  if (plan?.features?.length) {
    for (const f of plan.features as PlanFeature[]) {
      features[f.key] = {
        key: f.key,
        type: f.type as ResolvedFeature["type"],
        enabled: f.type === "boolean" ? (f.enabled ?? false) : true,
        limit: f.limit ?? 0,
        resetPeriod: (f.resetPeriod as ResolvedFeature["resetPeriod"]) ?? "never",
        overageAllowed: f.overageAllowed ?? false,
        overagePriceCents: f.overagePriceCents ?? 0,
        unit: f.unit ?? "",
        source: "plan"
      };
    }
  }

  // Apply tenant-level Entitlement overrides
  const overrides = await Entitlement.find({ tenantId }).lean();
  for (const ov of overrides) {
    const expired = ov.expiresAt && new Date(ov.expiresAt) < new Date();
    if (expired) continue;

    const existing = features[ov.key] ?? {
      key: ov.key,
      type: "boolean",
      enabled: false,
      limit: 0,
      resetPeriod: "never" as const,
      overageAllowed: false,
      overagePriceCents: 0,
      unit: "",
      source: "default" as const
    };

    features[ov.key] = {
      ...existing,
      source: "override",
      ...(ov.limitValue !== undefined && ov.limitValue !== null
        ? { limit: ov.limitValue as number, enabled: true }
        : {}),
      ...(ov.boolValue !== undefined && ov.boolValue !== null
        ? { enabled: ov.boolValue as boolean }
        : {})
    };
  }

  return {
    planId: plan?._id?.toString() ?? null,
    planName: plan?.name ?? "Free",
    planSlug: plan?.slug ?? "free",
    features,
    status: subscription?.status ?? "inactive"
  };
}

/**
 * Returns the resolved feature for a single key.
 * Returns a safe "disabled/zero" default if not found.
 */
export async function resolveFeature(
  tenantId: string,
  featureKey: string
): Promise<ResolvedFeature> {
  const plan = await resolveTenantPlan(tenantId);
  return (
    plan.features[featureKey] ?? {
      key: featureKey,
      type: "boolean",
      enabled: false,
      limit: 0,
      resetPeriod: "never",
      overageAllowed: false,
      overagePriceCents: 0,
      unit: "",
      source: "default"
    }
  );
}

/**
 * entitlement-engine.ts
 *
 * Replaces the hardcoded PLAN_DEFAULTS approach.
 * All entitlement checks flow through resolveTenantPlan() which reads
 * BillingPlan.features[] as the source of truth.
 *
 * Backward-compatible wrappers for the old entitlements.ts API are exported
 * so existing call-sites continue to work without modification.
 */

import { resolveFeature, resolveTenantPlan } from "./plan-resolver";

// ─── Core API ──────────────────────────────────────────────────────────────

/**
 * Get the effective value of a feature for a tenant.
 * Returns: number (for count/quota/storage), boolean (for boolean), or null.
 */
export async function getFeatureValue(
  tenantId: string,
  featureKey: string
): Promise<number | boolean | null> {
  const feature = await resolveFeature(tenantId, featureKey);
  if (feature.type === "boolean") return feature.enabled;
  return feature.limit;
}

/**
 * Check if a boolean feature is enabled.
 */
export async function isFeatureEnabled(tenantId: string, featureKey: string): Promise<boolean> {
  const feature = await resolveFeature(tenantId, featureKey);
  if (feature.type === "boolean") return feature.enabled;
  return feature.limit > 0;
}

/**
 * Check a numeric limit. Returns { allowed, current, limit }.
 */
export async function checkFeatureLimit(
  tenantId: string,
  featureKey: string,
  currentCount: number
): Promise<{ allowed: boolean; current: number; limit: number }> {
  const feature = await resolveFeature(tenantId, featureKey);
  const limit = feature.limit;
  return { allowed: currentCount < limit, current: currentCount, limit };
}

/**
 * Assert a feature is available — throws if not.
 */
export async function assertFeature(
  tenantId: string,
  featureKey: string,
  currentCount?: number
): Promise<void> {
  const feature = await resolveFeature(tenantId, featureKey);

  if (feature.type === "boolean") {
    if (!feature.enabled) {
      throw new Error(`Feature "${featureKey}" is not available on your current plan.`);
    }
    return;
  }

  if (currentCount !== undefined && feature.limit > 0) {
    if (currentCount >= feature.limit) {
      throw new Error(
        `Limit reached for "${featureKey}": ${currentCount}/${feature.limit} on your current plan.`
      );
    }
  }
}

/**
 * Get a complete snapshot of all features for a tenant.
 */
export async function getUsageSnapshot(tenantId: string) {
  return resolveTenantPlan(tenantId);
}

