/**
 * entitlements.ts
 *
 * Backward-compatible entitlements API.
 * Internally delegates to the new entitlement-engine which reads
 * BillingPlan.features[] — not PLAN_DEFAULTS.
 *
 * The old PLAN_DEFAULTS dictionary is preserved here ONLY as a migration
 * fallback for tenants whose plans have no features[] yet.
 * Once all plans are migrated via the seed script, this fallback can be removed.
 */

import { connectToDatabase } from "@/lib/mongodb";
import { Entitlement, TenantSubscription, BillingPlan } from "@/lib/models";
import { logger } from "@/lib/logger";

import {
  getFeatureValue,
  isFeatureEnabled,
  checkFeatureLimit,
  assertFeature
} from "@/lib/billing/entitlement-engine";
import { setEntitlementOverride as _setOverride } from "./billing/plan-resolver";

export type { FeatureKey as EntitlementKey } from "@/lib/billing/feature-registry";

// ─── Legacy PLAN_DEFAULTS — migration fallback only ───────────────────────────
// New code must NOT read from this. It remains only to bootstrap tenants
// that have not yet been migrated to feature-based plans.

const PLAN_DEFAULTS_FALLBACK: Record<string, Record<string, number | boolean>> = {
  free: {
    max_channels: 2, max_agents: 1, max_bots: 1, max_team_members: 3,
    monthly_message_limit: 100, knowledge_enabled: false, advanced_ai: false,
    instagram_enabled: false, whatsapp_enabled: false, facebook_enabled: false,
    telegram_enabled: true, qdrant_search: false, api_access: false, white_label: false
  },
  starter: {
    max_channels: 5, max_agents: 5, max_bots: 3, max_team_members: 10,
    monthly_message_limit: 1000, knowledge_enabled: true, advanced_ai: false,
    instagram_enabled: true, whatsapp_enabled: true, facebook_enabled: true,
    telegram_enabled: true, qdrant_search: false, api_access: true, white_label: false
  },
  pro: {
    max_channels: 20, max_agents: 25, max_bots: 10, max_team_members: 50,
    monthly_message_limit: 10000, knowledge_enabled: true, advanced_ai: true,
    instagram_enabled: true, whatsapp_enabled: true, facebook_enabled: true,
    telegram_enabled: true, qdrant_search: true, api_access: true, white_label: false
  },
  enterprise: {
    max_channels: 999, max_agents: 999, max_bots: 999, max_team_members: 999,
    monthly_message_limit: 999999, knowledge_enabled: true, advanced_ai: true,
    instagram_enabled: true, whatsapp_enabled: true, facebook_enabled: true,
    telegram_enabled: true, qdrant_search: true, api_access: true, white_label: true
  }
};

/** @internal Map old boolean key names to new feature keys */
const KEY_ALIAS: Record<string, string> = {
  advanced_ai_enabled: "advanced_ai",
  instagram_enabled: "max_instagram_accounts",
  whatsapp_enabled: "max_whatsapp_numbers",
  facebook_enabled: "max_facebook_pages",
  telegram_enabled: "max_telegram_channels",
  qdrant_enabled: "qdrant_search",
  api_access_enabled: "api_access",
  white_label_enabled: "white_label",
  knowledge_enabled: "knowledge_enabled",
  monthly_message_limit: "ai_messages"
};

function resolveKey(key: string): string {
  return KEY_ALIAS[key] ?? key;
}

// ─── Core helpers ──────────────────────────────────────────────────────────────

/**
 * Get the effective value for an entitlement key.
 * Delegates to the new entitlement-engine; falls back to PLAN_DEFAULTS_FALLBACK
 * if the plan has no features defined yet (migration period).
 */
export async function getEntitlement(
  tenantId: string,
  key: string
): Promise<number | boolean | null> {
  await connectToDatabase();

  // Check tenant-level Entitlement override first (legacy table)
  const override = await Entitlement.findOne({ tenantId, key }).lean();
  if (override) {
    const expired = override.expiresAt && new Date(override.expiresAt) < new Date();
    if (!expired) {
      return override.limitValue !== undefined ? (override.limitValue as number)
        : (override.boolValue as boolean) ?? null;
    }
  }

  // Try the new engine
  const normalizedKey = resolveKey(key);
  const val = await getFeatureValue(tenantId, normalizedKey);
  if (val !== null) return val;

  // Migration fallback: read from PLAN_DEFAULTS_FALLBACK
  const subscription = await TenantSubscription.findOne({ tenantId }).populate("planId").lean();
  const planName = ((subscription?.planId as any)?.name ?? "free").toLowerCase();
  const defaults = PLAN_DEFAULTS_FALLBACK[planName] ?? PLAN_DEFAULTS_FALLBACK.free;
  return defaults[key] ?? PLAN_DEFAULTS_FALLBACK.free[key] ?? null;
}

export async function checkNumericEntitlement(
  tenantId: string,
  key: string,
  currentCount: number
): Promise<{ allowed: boolean; current: number; limit: number }> {
  return checkFeatureLimit(tenantId, resolveKey(key), currentCount);
}

export async function checkBoolEntitlement(tenantId: string, key: string): Promise<boolean> {
  return isFeatureEnabled(tenantId, resolveKey(key));
}

export async function assertEntitlement(
  tenantId: string,
  key: string,
  currentCount?: number
): Promise<void> {
  return assertFeature(tenantId, resolveKey(key), currentCount);
}

// ─── Seed & override helpers ──────────────────────────────────────────────────

/**
 * Seed default entitlements for a tenant based on plan name.
 * @deprecated After full migration, plans should have features[] embedded.
 * This is only needed for the legacy Entitlement table path.
 */
export async function seedEntitlementsForPlan(
  tenantId: string,
  planName: string,
  planId?: string
): Promise<void> {
  await connectToDatabase();
  const defaults = PLAN_DEFAULTS_FALLBACK[planName.toLowerCase()] ?? PLAN_DEFAULTS_FALLBACK.free;

  const ops = Object.entries(defaults).map(([key, value]) => ({
    updateOne: {
      filter: { tenantId, key, isOverride: { $ne: true } },
      update: {
        $set: {
          tenantId,
          key,
          ...(typeof value === "number" ? { limitValue: value } : { boolValue: value }),
          ...(planId ? { planId } : {}),
          isOverride: false
        }
      },
      upsert: true
    }
  }));

  await Entitlement.bulkWrite(ops as any[]);
  logger.info("entitlements.seeded", { tenantId, planName });
}

/**
 * Set a tenant-level override (admin use).
 * Writes to both the legacy Entitlement table and is reflected in the new engine.
 */
export async function setEntitlementOverride(
  tenantId: string,
  key: string,
  value: number | boolean,
  expiresAt?: Date
): Promise<void> {
  await connectToDatabase();
  await Entitlement.findOneAndUpdate(
    { tenantId, key },
    {
      $set: {
        tenantId,
        key,
        ...(typeof value === "number" ? { limitValue: value } : { boolValue: value }),
        isOverride: true,
        ...(expiresAt ? { expiresAt } : {})
      }
    },
    { upsert: true }
  );
}

/**
 * plan-resolver.ts
 *
 * Resolves a tenant's current plan and its features.
 * BillingPlan.features[] is the single source of truth.
 * PLAN_DEFAULTS is no longer consulted here.
 */

import { connectToDatabase } from "@/lib/mongodb";
import { TenantSubscription, BillingPlan, Entitlement } from "@/lib/models";
import type { PlanFeature } from "@/lib/models/billing-plan";

export interface ResolvedFeature {
  key: string;
  type: "boolean" | "quota" | "count" | "storage" | "metered";
  enabled: boolean;
  limit: number;
  resetPeriod: "monthly" | "yearly" | "never";
  overageAllowed: boolean;
  overagePriceCents: number;
  unit: string;
  source: "plan" | "override" | "default";
}

export interface ResolvedPlan {
  planId: string | null;
  planName: string;
  planSlug: string;
  features: Record<string, ResolvedFeature>;
  status: string;
}

/**
 * Resolves all features for a tenant.
 * Priority: tenant-level Entitlement override > plan features > safe defaults.
 */
export async function resolveTenantPlan(tenantId: string): Promise<ResolvedPlan> {
  await connectToDatabase();

  const subscription = await TenantSubscription.findOne({ tenantId })
    .populate("planId")
    .lean();

  const plan = subscription?.planId as any;
  const features: Record<string, ResolvedFeature> = {};

  // Build feature map from plan features[]
  if (plan?.features?.length) {
    for (const f of plan.features as PlanFeature[]) {
      features[f.key] = {
        key: f.key,
        type: f.type as ResolvedFeature["type"],
        enabled: f.type === "boolean" ? (f.enabled ?? false) : true,
        limit: f.limit ?? 0,
        resetPeriod: (f.resetPeriod as ResolvedFeature["resetPeriod"]) ?? "never",
        overageAllowed: f.overageAllowed ?? false,
        overagePriceCents: f.overagePriceCents ?? 0,
        unit: f.unit ?? "",
        source: "plan"
      };
    }
  }

  // Apply tenant-level Entitlement overrides
  const overrides = await Entitlement.find({ tenantId }).lean();
  for (const ov of overrides) {
    const expired = ov.expiresAt && new Date(ov.expiresAt) < new Date();
    if (expired) continue;

    const existing = features[ov.key] ?? {
      key: ov.key,
      type: "boolean" as const,
      enabled: false,
      limit: 0,
      resetPeriod: "never" as const,
      overageAllowed: false,
      overagePriceCents: 0,
      unit: "",
      source: "default" as const
    };

    features[ov.key] = {
      ...existing,
      source: "override",
      ...(ov.limitValue !== undefined && ov.limitValue !== null
        ? { limit: ov.limitValue as number, enabled: true }
        : {}),
      ...(ov.boolValue !== undefined && ov.boolValue !== null
        ? { enabled: ov.boolValue as boolean }
        : {})
    };
  }

  return {
    planId: plan?._id?.toString() ?? null,
    planName: plan?.name ?? "Free",
    planSlug: plan?.slug ?? "free",
    features,
    status: subscription?.status ?? "inactive"
  };
}

/**
 * Returns the resolved feature for a single key.
 */
export async function resolveFeature(
  tenantId: string,
  featureKey: string
): Promise<ResolvedFeature> {
  const plan = await resolveTenantPlan(tenantId);
  return (
    plan.features[featureKey] ?? {
      key: featureKey,
      type: "boolean",
      enabled: false,
      limit: 0,
      resetPeriod: "never",
      overageAllowed: false,
      overagePriceCents: 0,
      unit: "",
      source: "default"
    }
  );
}

/**
 * Set a tenant-level entitlement override via the Entitlement model.
 * This is the admin-facing function; it's also exposed from entitlements.ts.
 */
export async function setEntitlementOverride(
  tenantId: string,
  key: string,
  value: number | boolean,
  expiresAt?: Date
): Promise<void> {
  await connectToDatabase();
  const { Entitlement } = await import("@/lib/models");
  await Entitlement.findOneAndUpdate(
    { tenantId, key },
    {
      $set: {
        tenantId,
        key,
        ...(typeof value === "number" ? { limitValue: value } : { boolValue: value }),
        isOverride: true,
        ...(expiresAt ? { expiresAt } : {})
      }
    },
    { upsert: true }
  );
}

/**
 * quota.ts
 *
 * Backward-compatible quota API for AI messages.
 * Internally delegates to the generic usage-engine.
 *
 * Existing call-sites (assertAndReserveQuota, getQuotaStatus, flushQuotaToMongo)
 * continue to work unchanged.
 */

import { FEATURE_KEYS } from "@/lib/billing/feature-registry";
import {
  reserveUsage,
  getFeatureUsage,
  flushUsageToMongo as _flushUsageToMongo
} from "@/lib/billing/usage-engine";
import { connectToDatabase } from "@/lib/mongodb";
import { TenantSubscription } from "@/lib/models";
import { logger } from "@/lib/logger";

export function quotaRedisKey(tenantId: string): string {
  const now = new Date();
  const yyyyMM = `${now.getUTCFullYear()}-${String(now.getUTCMonth() + 1).padStart(2, "0")}`;
  return `usage:${FEATURE_KEYS.AI_MESSAGES}:${tenantId}:${yyyyMM}`;
}

/**
 * Atomically assert and reserve one AI message quota slot.
 * Delegates to the generic usage-engine with featureKey = "ai_messages".
 *
 * Backward compatibility preserved: throws the same Arabic error message.
 */
export async function assertAndReserveQuota(tenantId: string): Promise<void> {
  try {
    await reserveUsage(tenantId, FEATURE_KEYS.AI_MESSAGES, 1, {
      failOpenForPaidPlans: true
    });
  } catch (err) {
    const msg = err instanceof Error ? err.message : "";
    if (msg.includes("Usage limit exceeded")) {
      throw new Error("تم استهلاك رصيد رسائل AI لهذه الخطة. اشتر باقة رسائل إضافية أو غيّر الخطة.");
    }
    throw err;
  }
}

/**
 * Get current quota status for AI messages.
 */
export async function getQuotaStatus(tenantId: string): Promise<{
  used: number;
  limit: number;
  redisCount: number;
  source: "redis" | "mongo";
}> {
  const { used, limit, source } = await getFeatureUsage(tenantId, FEATURE_KEYS.AI_MESSAGES);
  return { used, limit, redisCount: used, source };
}

/**
 * Flush Redis counter to MongoDB immediately.
 */
export async function flushQuotaToMongo(tenantId: string): Promise<void> {
  await _flushUsageToMongo(tenantId, FEATURE_KEYS.AI_MESSAGES);
}

