  return subs.map((sub: any) => ({
    id: sub._id.toString(),
    tenantName: sub.tenantId?.name || "Unknown",
    tenantSlug: sub.tenantId?.slug || "",
    planName: sub.planId?.name || "الخطة المجانية",
